// Boundary lookup: stem -> FieldKind. Linear scan over ~70 entries, called
// once per NPY at load time. The ONE place a filename string is compared.
inline std::optional<FieldKind> FindFieldByStem(std::string_view stem) {
    for (const auto& fs : kFieldCatalog)
        if (fs.stem == stem) return fs.kind;
    return std::nullopt;
}

// kFieldCatalog is emitted in FieldKind order, so the ordinal indexes it.
inline const FieldSpec& FieldSpecFor(FieldKind k) {
    return kFieldCatalog[static_cast<std::size_t>(k)];
}

